const ctx = $('Switch_Rol').first().json;
const tickets = $input.all().map(i => i.json).filter(t => t && t.id);

const cola = tickets.slice(0, 20).map(t => ({
  id: t.id, folio: t.folio, estatus: t.estatus,
  sla: t.sla_status, vencido: t.sla_vencido,
  prioridad: t.prioridad,
  desc: (t.descripcion || '').slice(0, 80),
  area: t.cat_nivel1 || null
}));

return [{ json: {
  ...ctx,
  tickets_data: JSON.stringify(cola),
  ticket_detalle: ''
}}];

