const item = $input.first().json;

// Si no hay imagen, pasar todo sin cambios
if (!item.imagen) {
  return [{ json: { ...item, imagen_descripcion: '' } }];
}

// Llamar Gemini Vision con la imagen base64
const base64 = item.imagen;

// Extraer tipo y datos del data URL (ej: "data:image/jpeg;base64,/9j/...")
const match = base64.match(/^data:(image\/\w+);base64,(.+)$/);
if (!match) {
  return [{ json: { ...item, imagen_descripcion: '(imagen recibida pero formato inválido)' } }];
}

const mimeType = match[1];
const imageData = match[2];

const apiKey = $env.GEMINI_API_KEY;
const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`;

const response = await fetch(url, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    contents: [{
      parts: [
        {
          text: 'Describe detalladamente esta imagen en español. Es parte de un reporte de soporte técnico en una tienda de retail. Incluye: qué se ve, si hay error visible en pantalla, estado del equipo, cualquier dato relevante para soporte técnico. Sé conciso pero preciso.'
        },
        {
          inline_data: {
            mime_type: mimeType,
            data: imageData
          }
        }
      ]
    }],
    generationConfig: { temperature: 0.1, maxOutputTokens: 300 }
  })
});

const result = await response.json();
const descripcion = result?.candidates?.[0]?.content?.parts?.[0]?.text ?? '(no se pudo analizar la imagen)';

return [{
  json: {
    ...item,
    imagen_descripcion: descripcion
  }
}];
